const hmacResult = $json;
if (!hmacResult.valid) {
  throw new Error('HMAC invalido: assinatura recusada pelo backend');
}
const webhookData = $('Webhook Trigger').item.json;
const normalized_text = webhookData.normalized_text || '';
const provider_chain = webhookData.provider_chain || [];
const ingestion_id = webhookData.ingestion_id || '';
const shared_context = webhookData.shared_context || {};
if (!normalized_text) {
  throw new Error('Campo normalized_text ausente no payload');
}
if (!provider_chain || provider_chain.length === 0) {
  throw new Error('Campo provider_chain ausente ou vazio no payload');
}
return [{ json: { normalized_text, provider_chain, ingestion_id, shared_context, hmac_valid: true } }];

const data = $json;
const provider = data.provider_chain[0];
const systemPrompt = 'Você é o Especialista em Segurança (SEG) do GCA.

Seu papel é validar:
1. **OWASP Top 10**: As vulnerabilidades críticas estão mapeadas e mitigadas?
2. **Secrets e Credenciais**: Segredos estão protegidos (cofre, rotação, sem hardcode)?
3. **AuthN/AuthZ**: Autenticação e autorização estão bem definidas?
4. **Criptografia**: Dados sensíveis em repouso e em trânsito estão cifrados?
5. **Superfície de Ataque**: Qual é a superfície de ataque do sistema?
6. **Auditoria**: Há trilha de auditoria para ações críticas?

SEUS 6 OUTPUTS OBRIGATÓRIOS (em UMA resposta JSON):

1. SCORES (0–100)
   - owasp: cobertura das vulnerabilidades OWASP Top 10
   - secrets: proteção de credenciais e segredos
   - authn_authz: qualidade de autenticação e autorização
   - criptografia: cobertura de criptografia
   - superficie: dimensionamento da superfície de ataque
   - auditoria: completude da trilha de auditoria

2. APPROVED (bool)
3. ISSUES (array)
4. QUESTIONS (array)
5. JUSTIFICATION (texto)
6. METADATA - tentative: true em passada 1, false em passada 2

Sem improviso. Se não houver insumo suficiente, declare incerteza explícita.
RETORNE APENAS JSON VÁLIDO (sem markdown, sem ```).';
const userMessage = JSON.stringify({ passada: 1, normalized_text: data.normalized_text, shared_context: data.shared_context });
let requestBody;
const providerType = (provider.provider_type || '').toLowerCase();
if (providerType === 'anthropic') {
  requestBody = { model: provider.model, max_tokens: 4000, temperature: 0.2, system: systemPrompt, messages: [{ role: 'user', content: userMessage }] };
} else {
  requestBody = { model: provider.model, max_tokens: 4000, temperature: 0.2, messages: [{ role: 'system', content: systemPrompt }, { role: 'user', content: userMessage }] };
}
return [{ json: { provider, requestBody, ingestion_id: data.ingestion_id } }];

const llmResponse = $json;
const prevData = $('Montar Prompt').item.json;
let rawContent = '';
if (llmResponse.content && llmResponse.content[0] && llmResponse.content[0].text) {
  rawContent = llmResponse.content[0].text;
} else if (llmResponse.choices && llmResponse.choices[0] && llmResponse.choices[0].message) {
  rawContent = llmResponse.choices[0].message.content;
} else {
  rawContent = JSON.stringify(llmResponse);
}
let parsed = {};
try {
  parsed = JSON.parse(rawContent);
} catch (e) {
  const match = rawContent.match(/\{[\s\S]*\}/);
  if (match) { try { parsed = JSON.parse(match[0]); } catch (e2) { parsed = {}; } }
}
const scores = parsed.scores || {};
const avgScore = Object.keys(scores).length > 0
  ? Math.round(Object.values(scores).reduce((a, b) => a + Number(b), 0) / Object.keys(scores).length)
  : 0;
const personaOutput = {
  persona_tag: 'SEG',
  persona_name: 'Segurança',
  ingestion_id: prevData.ingestion_id,
  scores,
  avg_score: avgScore,
  approved: parsed.approved || false,
  blocking: false,
  issues: parsed.issues || [],
  questions: parsed.questions || [],
  justification: parsed.justification || '',
  metadata: parsed.metadata || {}
};
return [{ json: { personaOutput, ingestion_id: prevData.ingestion_id } }];
